def generate_attestation_letter(report: dict, signatory: str, signatory_title: str) -> str:
    s = report["summary"]
    period = report["reporting_period"]
    violations = s["violation_count"]

    status_line = (
        "No residency violations were detected during this period."
        if violations == 0
        else f"WARNING: {violations} request(s) were routed outside the required region. Details are provided in the accompanying technical report."
    )

    return f"""DATA RESIDENCY ATTESTATION LETTER

Organisation: {report['organisation']}
Reporting Period: {period['start'][:10]} to {period['end'][:10]}
Required Region: {report['required_region']}
Generated: {report['generated_at'][:10]}

ATTESTATION

This letter confirms that {report['organisation']} has implemented technical
and organisational measures to ensure that all Claude API requests containing
personal data are routed exclusively to infrastructure located in the
{report['required_region']} region during the above reporting period.

SUMMARY STATISTICS

  Total API requests in scope: {s['total_requests']:,}
  Requests routed to required region: {s['compliant_requests']:,}
  Compliance rate: {s['compliance_rate_pct']}%

{status_line}

This attestation is based on API access logs collected at the application layer
and verified against endpoint TLS certificates. The underlying log data is
retained for 2 years and available for regulator inspection upon request.

Evidence Hash (SHA-256 of underlying log data):
{report['evidence_hash']}

Signed: {signatory}
Title: {signatory_title}
Date: {report['generated_at'][:10]}
"""
